"use client"

import { useEffect, useState } from "react"
import Link from "next/link"
import { AdminLayout } from "@/components/admin-layout"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Trash2, Edit2, Plus } from "lucide-react"

interface Deal {
  _id: string
  address: string
  purchasePrice: number
  arv: number
  profitPercent: number
  status: "PASS" | "FAIL"
}

export default function DealsPage() {
  const [deals, setDeals] = useState<Deal[]>([])
  const [filter, setFilter] = useState<"ALL" | "PASS" | "FAIL">("ALL")
  const [isCreating, setIsCreating] = useState(false)
  const [editingDeal, setEditingDeal] = useState<Deal | null>(null)

  const [form, setForm] = useState({
    address: "",
    purchasePrice: 0,
    arv: 0,
    profitPercent: 0,
    status: "PASS" as "PASS" | "FAIL",
  })

  // Load deals
  useEffect(() => {
    fetch("/api/deals")
      .then(res => res.json())
      .then(setDeals)
  }, [])

  const filteredDeals = deals.filter(d =>
    filter === "ALL" ? true : d.status === filter
  )

  const resetForm = () => {
    setForm({
      address: "",
      purchasePrice: 0,
      arv: 0,
      profitPercent: 0,
      status: "PASS",
    })
    setIsCreating(false)
    setEditingDeal(null)
  }

  // CREATE
  const handleCreate = async () => {
    const res = await fetch("/api/deals", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(form),
    })

    const deal = await res.json()
    setDeals([deal, ...deals])
    resetForm()
  }

  // UPDATE
  const handleUpdate = async () => {
    if (!editingDeal) return

    const res = await fetch(`/api/deals/${editingDeal._id}`, {
      method: "PATCH",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(form),
    })

    const updated = await res.json()
    setDeals(deals.map(d => (d._id === updated._id ? updated : d)))
    resetForm()
  }

  // DELETE
  const handleDelete = async (id: string) => {
    await fetch(`/api/deals/${id}`, { method: "DELETE" })
    setDeals(deals.filter(d => d._id !== id))
  }

  const startEdit = (deal: Deal) => {
    setEditingDeal(deal)
    setIsCreating(false)
    setForm({
      address: deal.address,
      purchasePrice: deal.purchasePrice,
      arv: deal.arv,
      profitPercent: deal.profitPercent,
      status: deal.status,
    })
  }

  return (
    <AdminLayout>
      <div className="p-8 space-y-6">

        <div className="flex justify-between items-center">
          <div>
            <h1 className="text-4xl font-bold">Deals</h1>
            <p className="text-muted-foreground">Manage all property deals</p>
          </div>
          <Button onClick={() => { resetForm(); setIsCreating(true) }}>
            <Plus className="w-4 h-4 mr-2" /> New Deal
          </Button>
        </div>

        {(isCreating || editingDeal) && (
          <Card>
            <CardHeader>
              <CardTitle>{editingDeal ? "Edit Deal" : "Create Deal"}</CardTitle>
            </CardHeader>
            <CardContent className="grid grid-cols-2 gap-4">
              <div>
                <Label>Address</Label>
                <Input value={form.address} onChange={e => setForm({ ...form, address: e.target.value })} />
              </div>
              <div>
                <Label>Purchase Price</Label>
                <Input type="number" value={form.purchasePrice}
                  onChange={e => setForm({ ...form, purchasePrice: Number(e.target.value) })} />
              </div>
              <div>
                <Label>ARV</Label>
                <Input type="number" value={form.arv}
                  onChange={e => setForm({ ...form, arv: Number(e.target.value) })} />
              </div>
              <div>
                <Label>Profit %</Label>
                <Input type="number" value={form.profitPercent}
                  onChange={e => setForm({ ...form, profitPercent: Number(e.target.value) })} />
              </div>
              <div className="col-span-2">
                <Label>Status</Label>
                <select
                  className="w-full border rounded px-3 py-2"
                  value={form.status}
                  onChange={e => setForm({ ...form, status: e.target.value as any })}
                >
                  <option value="PASS">PASS</option>
                  <option value="FAIL">FAIL</option>
                </select>
              </div>
              <div className="col-span-2 flex justify-end gap-2">
                <Button variant="outline" onClick={resetForm}>Cancel</Button>
                <Button onClick={editingDeal ? handleUpdate : handleCreate}>
                  {editingDeal ? "Update" : "Create"}
                </Button>
              </div>
            </CardContent>
          </Card>
        )}

        <div className="flex gap-2">
          {["ALL", "PASS", "FAIL"].map(f => (
            <Button
              key={f}
              size="sm"
              variant={filter === f ? "default" : "outline"}
              onClick={() => setFilter(f as any)}
            >
              {f}
            </Button>
          ))}
        </div>

        <Card>
          <CardHeader>
            <CardTitle>All Deals</CardTitle>
            <CardDescription>{filteredDeals.length} deals</CardDescription>
          </CardHeader>
          <CardContent>
            <table className="w-full">
              <thead>
                <tr className="border-b">
                  <th>Address</th>
                  <th className="text-right">Price</th>
                  <th className="text-right">ARV</th>
                  <th className="text-right">Profit %</th>
                  <th>Status</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {filteredDeals.map(d => (
                  <tr key={d._id} className="border-b">
                    <td>{d.address}</td>
                    <td className="text-right">${d.purchasePrice.toLocaleString()}</td>
                    <td className="text-right">${d.arv.toLocaleString()}</td>
                    <td className="text-right">{d.profitPercent}%</td>
                    <td>{d.status}</td>
                    <td className="flex gap-2">
                      <button onClick={() => startEdit(d)}><Edit2 className="w-4 h-4" /></button>
                      <button onClick={() => handleDelete(d._id)}><Trash2 className="w-4 h-4" /></button>
                      <Link href={`/admin/deals/${d._id}`}>View</Link>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </CardContent>
        </Card>

      </div>
    </AdminLayout>
  )
}
